#!/usr/bin/env python3
"""Enrich books 40-49: Matthew through Ephesians."""
import json, os

OUT = os.path.join(os.path.dirname(__file__), '..', 'data', 'books', 'introductions')

ENRICHMENTS = {
  "matthew": {
    "key_people": [
      {"name": "Jesus Christ", "role": "The central figure of the book — Son of David, Son of Abraham, Immanuel, and the Son of God whose teaching, miracles, death, and resurrection constitute the new and greater Torah"},
      {"name": "Matthew (Levi)", "role": "The tax collector called by Jesus (9:9) who is traditionally identified as the author; his background as a record-keeper likely accounts for the book's meticulous structure and use of OT fulfilment texts"},
      {"name": "John the Baptist", "role": "The Elijah-figure who prepares Jesus' way, baptizes him, and whose imprisonment and death foreshadow Jesus' own fate"},
      {"name": "Peter", "role": "The disciple who receives the keys of the kingdom (16:19) and whose confession at Caesarea Philippi is the book's theological turning point"},
      {"name": "The Pharisees and Scribes", "role": "The primary antagonists whose growing opposition to Jesus structures the second half of the book; their hardness of heart is a warning to Matthew's own community"}
    ],
    "context": "Matthew was written c. AD 80–90, probably in Syrian Antioch, for a Jewish-Christian community navigating its relationship to its Jewish heritage after the destruction of the temple (AD 70). The book is deeply rooted in OT Scripture — containing more direct OT citations than any other gospel — and structured around five great teaching discourses that parallel the five books of Moses. Its primary concern is to show that Jesus is the fulfilment of all OT expectation.",
    "christ_connection": "Matthew is the most explicitly fulfilment-focused gospel, with ten signature formula-quotations ('this happened to fulfil what was spoken by the prophet...'). Jesus is presented as the new Moses (the five discourses parallel the Pentateuch), the new Israel (recapitulating Israel's history), Son of David (opening genealogy), Immanuel (1:23; 28:20 form an inclusion), and the Son in whom all sonship is perfectly realised. The Sermon on the Mount (chs. 5-7) is Jesus' authoritative exposition of the Torah's true meaning — not abolishing but fulfilling.",
    "key_verses": [
      {"ref": "Matthew 1:23", "note": "'Behold, the virgin shall conceive and bear a son, and they shall call his name Immanuel (which means, God with us)' — the book's opening christological declaration, fulfilled in 28:20"},
      {"ref": "Matthew 5:17", "note": "'Do not think that I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfil them' — Jesus' programmatic statement about his relationship to OT Scripture"},
      {"ref": "Matthew 16:18", "note": "'You are Peter, and on this rock I will build my church, and the gates of hell shall not prevail against it' — the founding declaration of the church"},
      {"ref": "Matthew 28:18-20", "note": "The Great Commission: all authority given to Christ, the command to disciple all nations, and the promise of his presence to the end of the age — the book's climactic conclusion"}
    ],
    "themes_detail": [
      {"title": "Jesus as the Fulfillment of the OT", "text": "Matthew's formula quotations are not proof-texts plucked from context but arguments that Jesus' life, death, and resurrection are the events toward which the entire OT narrative was pointing. He quotes from the Law, Prophets, and Writings, covering events as small as the flight to Egypt (2:15) and as large as the crucifixion (27:46). The point is not merely that isolated verses were predicted but that the whole OT story — of God dwelling with his people, of exodus and exile, of covenant and king — finds its resolution in the person of Jesus."},
      {"title": "The Kingdom of Heaven", "text": "Matthew uses the phrase 'kingdom of heaven' (a Jewish circumlocution for 'kingdom of God') more than any other gospel writer — 32 times. The kingdom is both present (it has come near, 4:17; is being entered, 5:20) and future (its coming is prayed for, 6:10; it will be inherited at the end, 25:34). Its character is paradoxical: it belongs to the poor in spirit and the persecuted (5:3, 10), advances without military force, and its citizens are those who do the Father's will. The parables of the kingdom (ch. 13) are Matthew's most sustained exploration of this paradox."},
      {"title": "Jesus as Teacher and the New Torah", "text": "The five discourses (chs. 5-7, 10, 13, 18, 24-25) are Matthew's structural backbone and parallel the Pentateuch. Jesus teaches 'as one who had authority, and not as their scribes' (7:29) — not citing precedent but speaking in the first person ('But I say to you'). The Sermon on the Mount is not a relaxation of the law's demands (the righteousness required exceeds that of the Pharisees, 5:20) but an exposition of what the law always meant when understood in terms of its inner intention rather than its external form. Jesus is the true and final teacher of Israel."},
      {"title": "The Mission to the Nations", "text": "Matthew opens with Gentile magi worshipping the infant Jesus and closes with the commission to disciple all nations — framing the entire book as a universal mission story. Within the book, Jesus ministers to a Canaanite woman (15:21-28), heals a centurion's servant (8:5-13), and declares the centurion's faith greater than any in Israel. The parable of the tenants (21:43) warns that the kingdom will be taken from unfaithful Israel and given to 'a people producing its fruits' — the multinational church. The Great Commission is not an addendum but the logical conclusion of Matthew's christology."}
    ]
  },

  "mark": {
    "key_people": [
      {"name": "Jesus Christ", "role": "The Son of God whose identity is announced at his baptism and transfiguration but kept secret from the crowds — the Markan 'messianic secret' resolves only at the cross when a Roman centurion confesses him as Son of God"},
      {"name": "Peter", "role": "The disciple whose voice is often heard behind Mark's vivid narratives; tradition identifies Mark as Peter's interpreter, and the book's eyewitness freshness reflects this"},
      {"name": "The Twelve", "role": "Disciples who consistently fail to understand Jesus — their incomprehension is a literary device that allows Jesus to explain further, and a mirror for Mark's own readers"}
    ],
    "context": "Mark is the earliest gospel, written c. AD 65–70, probably in Rome during the Neronian persecution. It is addressed primarily to Gentile Christians facing suffering and was written with urgency — the word 'immediately' (euthys) occurs 40 times. Mark's Christology is action-focused: Jesus is identified as Son of God from the opening verse, but the narrative shows who that means through relentless forward motion: miracle, conflict, journey, cross, resurrection.",
    "christ_connection": "Mark's entire narrative is built toward the cross: the Son of Man came 'to give his life as a ransom for many' (10:45) is the book's theological centrepiece, and the passion narrative (chs. 14-16) takes up more than a third of the book's final section. The messianic secret — Jesus repeatedly silencing those who identify him — is resolved at the cross, where a pagan soldier becomes the first human in the narrative to confess Jesus as Son of God (15:39). The resurrection is reported with striking brevity (16:1-8), leaving readers themselves to respond to the empty tomb.",
    "key_verses": [
      {"ref": "Mark 1:1", "note": "'The beginning of the gospel of Jesus Christ, the Son of God' — the book's thesis statement; 'Son of God' frames everything that follows"},
      {"ref": "Mark 8:29", "note": "Peter's confession 'You are the Christ' at Caesarea Philippi — the turning point after which Jesus begins teaching about the cross"},
      {"ref": "Mark 10:45", "note": "'The Son of Man came not to be served but to serve, and to give his life as a ransom for many' — the theological heart of Mark's christology: servant messiahship defined by substitutionary sacrifice"}
    ],
    "themes_detail": [
      {"title": "The Messianic Secret", "text": "Jesus repeatedly commands silence from those he heals and from demons who recognize him (1:25, 34, 44; 3:12; 5:43; 7:36; 8:30). This pattern — the Messianic Secret — has been interpreted variously, but its most likely function is christological: the full meaning of 'Son of God' and 'Christ' can only be understood in the light of the cross. Peter's confession (8:29) is immediately followed by Jesus' first passion prediction (8:31-33), and Peter's rebuke of the passion reveals that he has confessed the right title with the wrong content. Identity and mission are inseparable in Mark."},
      {"title": "The Way of the Cross as Discipleship", "text": "The central section of Mark (8:31-10:52) is structured as a journey to Jerusalem bookended by two blind men healed (8:22-26; 10:46-52). Between these two healing stories, three passion predictions are each followed by the disciples failing to understand and Jesus correcting their theology with a call to servant-leadership. Discipleship in Mark is not primarily intellectual assent but following on the way of the cross: 'If anyone would come after me, let him deny himself and take up his cross and follow me' (8:34). The blind men who can see frame a section where the seeing disciples are blind."},
      {"title": "The Authority of Jesus Over All Powers", "text": "Mark's opening section (1:14-3:6) is a compressed sequence of Jesus exercising authority over unclean spirits (1:23-26), disease (1:29-31, 40-45), paralysis (2:1-12), and religious tradition (2:15-3:6). This authority is total: nature (4:35-41), death (5:21-43), distance (7:24-30), and feeding thousands (6:30-44; 8:1-10). The cumulative effect is that Jesus acts as YHWH acts in the OT — with sovereign power over everything that enslaves, defiles, or destroys human beings. His authority over demons (the 'strong man' of 3:27) frames his entire ministry as an invasion of enemy territory."},
      {"title": "The Unexpected Messiah: Suffering as Glory", "text": "Mark subverts every Jewish expectation of what the Messiah would do. He does not overthrow Rome; he is arrested, mocked, condemned, and crucified. The inscription above his cross — 'King of the Jews' — is meant sarcastically but is theologically accurate. The paradox is Mark's central theological claim: the cross is not the defeat of the Son of God but the precise point at which his identity is most fully revealed. The centurion's confession (15:39) comes specifically at the moment of Jesus' death — Mark's narrative ensures that 'Son of God' can never again be understood apart from crucifixion."}
    ]
  },

  "luke": {
    "key_people": [
      {"name": "Jesus Christ", "role": "The Son of God who is also the perfect human — Luke's Jesus weeps, prays, heals, and welcomes the excluded with a warmth not found in the other gospels"},
      {"name": "Mary", "role": "Her Magnificat (1:46-55) is the book's first great theological statement; her pondering posture (2:19, 51) models the attentive response to God's word that Luke prizes"},
      {"name": "The Disciples", "role": "Including the Seventy-Two sent out in 10:1-20 — Luke's mission theology extends beyond the Twelve to a larger group that anticipates the church's universal mission"},
      {"name": "Various Marginalised Figures", "role": "Women, tax collectors, Samaritans, the poor, the sick — Luke systematically includes those excluded by the religious establishment as the primary recipients of Jesus' ministry"}
    ],
    "context": "Luke was written c. AD 80-90, addressed to 'Theophilus' and intended for a Gentile Christian audience. It is the first volume of a two-volume work (Luke-Acts) that traces the movement of the gospel from Galilee to Jerusalem to Rome. Luke is the most literary of the gospels, written in the most sophisticated Greek, and shows particular interest in prayer, the Holy Spirit, the poor, women, and the universal scope of salvation.",
    "christ_connection": "Luke frames Jesus' entire ministry as the fulfilment of Isaiah's Jubilee vision: at his inaugural sermon in Nazareth (4:16-21) he reads Isaiah 61:1-2 and declares 'today this scripture has been fulfilled in your hearing.' The poor, the captive, the blind, and the oppressed are the specific recipients of the kingdom's arrival. The travel narrative (9:51-19:44) structures Jesus' journey to Jerusalem as the decisive Exodus movement — the 'departure' (exodus, 9:31) he discusses at the transfiguration. The risen Christ's exposition of the Scriptures on the road to Emmaus (24:27) frames the OT as a whole as pointing to him.",
    "key_verses": [
      {"ref": "Luke 1:46-47", "note": "The Magnificat opening: 'My soul magnifies the Lord, and my spirit rejoices in God my Savior' — the book's first christological declaration, sung by a peasant girl who understands the revolution God is beginning"},
      {"ref": "Luke 4:18-19", "note": "Jesus' Nazareth manifesto from Isaiah 61: 'The Spirit of the Lord is upon me... to proclaim the year of the Lord's favor' — his mission statement that frames all that follows"},
      {"ref": "Luke 15:20", "note": "The father's response to the prodigal: 'he ran and embraced him and kissed him' — the most complete picture in Scripture of the welcoming God who does not wait to be approached"},
      {"ref": "Luke 24:45", "note": "'Then he opened their minds to understand the Scriptures' — the risen Jesus as the key that unlocks the meaning of the entire OT"}
    ],
    "themes_detail": [
      {"title": "The Gospel for the Excluded", "text": "Luke systematically presents Jesus as turning toward those whom the religious establishment turned away: women (7:36-50; 8:1-3; 10:38-42), tax collectors (5:27-32; 15:1-2; 19:1-10), Samaritans (10:25-37; 17:11-19), Gentiles (4:25-27), and the poor (6:20; 16:19-31). This is not sentimental egalitarianism but a claim about the character of God's kingdom: it inverts the status hierarchies of both Jewish religious culture and Greco-Roman society. The reversal theme of the Magnificat (1:52-53) programs the entire book: the mighty are brought low; the humble are exalted."},
      {"title": "Prayer and the Holy Spirit", "text": "Luke mentions Jesus praying at every major turning point in his ministry: his baptism (3:21), before choosing the Twelve (6:12), at Caesarea Philippi (9:18), at the transfiguration (9:29), in Gethsemane (22:41), and from the cross (23:34, 46). This is not incidental but theological: Jesus' sonship is constituted and expressed in dependent prayer to the Father, and the Holy Spirit is consistently the Father's response (3:22; 11:13). The disciples' request 'teach us to pray' (11:1) is the hinge on which the book's spirituality turns."},
      {"title": "The Journey to Jerusalem and the Divine Necessity", "text": "The phrase 'it is necessary' (dei) occurs more in Luke than in any other gospel, expressing the divine necessity that governs Jesus' mission: he must be in his Father's house (2:49), must preach the kingdom (4:43), must suffer and be raised (9:22; 24:7, 26, 44). The travel narrative (9:51-19:44) is structured around Jesus 'setting his face toward Jerusalem' — a deliberate, purposeful movement that cannot be deflected. This Lukan emphasis on divine necessity is not fatalism but the theological conviction that Jesus' entire life was lived in conscious obedience to the Father's redemptive plan."},
      {"title": "The Universal Scope of Salvation", "text": "Simeon's declaration that Jesus is 'a light for revelation to the Gentiles and for glory to your people Israel' (2:32) programs Luke's entire two-volume work. Luke traces Jesus' genealogy back to Adam (not just Abraham, as in Matthew) — the universal human ancestor. The commission in Acts 1:8 ('to the ends of the earth') is the fulfilment of what the gospel narrates in embryo: Jesus' gracious reception of Samaritans, Gentiles, and those outside the covenant people are advance signs of what the Spirit will accomplish in Acts. Luke's story is the story of how salvation went global."}
    ]
  },

  "john": {
    "key_people": [
      {"name": "Jesus Christ", "role": "The pre-existent Logos who becomes flesh; John's 'I am' declarations (bread of life, light of the world, good shepherd, resurrection and life, way, truth, life, true vine) provide the book's christological architecture"},
      {"name": "The Beloved Disciple", "role": "The unnamed disciple who reclines at Jesus' breast at the Last Supper, stands at the cross, and first believes at the empty tomb — the ideal witness and model for the Johannine community"},
      {"name": "Mary Magdalene", "role": "First witness of the risen Jesus (20:11-18) and the first person commissioned to announce the resurrection — her apostolic role is explicit and prominent in John"},
      {"name": "Thomas", "role": "The doubting disciple whose confession 'My Lord and my God' (20:28) is the book's christological climax — the highest explicit Christology in all four gospels"}
    ],
    "context": "John was written c. AD 90-100, likely in Ephesus, for a community that had suffered expulsion from the synagogue (9:22; 12:42; 16:2). It is theologically the most developed of the four gospels, written by a community that has been living with the tradition for decades and has meditated deeply on its meaning. The book contains no birth narrative, no temptation, no Transfiguration, and no institution of the Supper — instead, a Prologue that places Jesus within the eternal divine life.",
    "christ_connection": "John's Christology is the highest in the NT: the Logos who was with God and was God (1:1), the I AM who predates Abraham (8:58), and the one who shares glory with the Father from before the world existed (17:5). The seven signs (2:1-11; 4:46-54; 5:1-15; 6:1-15; 6:16-21; 9:1-12; 11:1-44) are not merely miracles but epiphanies — moments when the glory of the incarnate Son of God becomes visible. The Farewell Discourse (chs. 14-17) is Jesus' most extensive self-disclosure in the Gospels, and the High Priestly Prayer (ch. 17) gives unparalleled access to the inner life of the Son's relationship with the Father.",
    "key_verses": [
      {"ref": "John 1:1", "note": "'In the beginning was the Word, and the Word was with God, and the Word was God' — the book's opening declaration of the eternal pre-existence and divine identity of Jesus Christ"},
      {"ref": "John 3:16", "note": "'For God so loved the world that he gave his only Son, that whoever believes in him should not perish but have eternal life' — the most memorised verse in Scripture; the gospel in miniature"},
      {"ref": "John 11:25-26", "note": "'I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live' — Jesus' self-identification before the greatest sign, the raising of Lazarus"},
      {"ref": "John 20:28", "note": "Thomas's confession 'My Lord and my God!' — the book's christological climax, the highest Christology in any gospel, elicited by the physical evidence of the resurrection"}
    ],
    "themes_detail": [
      {"title": "The Incarnation and the Glory of God Made Visible", "text": "John 1:14 is the theological heart of the book: 'The Word became flesh and dwelt among us, and we have seen his glory.' The Tabernacle/Temple imagery is deliberate — the Shekinah glory that filled the wilderness tabernacle and Solomon's temple has now taken up residence in a human body. The seven signs are not just miracles but theophanic events — moments when the eternal glory of the Son of God becomes visible through specific, concrete acts. Each sign is accompanied by teaching that explains what kind of glory is being revealed."},
      {"title": "Belief and Unbelief as the Book's Central Division", "text": "John's gospel is structured by the response to Jesus: some believe and receive life; others reject and remain in darkness. The pattern repeats through the signs and discourses: the disciples believe (2:11); the religious leaders reject (5:18; 7:1; 10:31-39); 'the world' receives its own judgment by its response to the light (3:19-21). This is not fatalism but a call to response: John's stated purpose (20:30-31) is to produce belief, and the entire book is organized as an extended invitation to trust the one who is the resurrection and the life."},
      {"title": "The Holy Spirit as the Continuing Presence of Jesus", "text": "The Paraclete sayings in the Farewell Discourse (14:16-17, 26; 15:26-27; 16:7-15) are John's most developed pneumatology. The Spirit is 'another Paraclete' (14:16) — the same kind of helping presence that Jesus has been, continuing his ministry after the ascension. The Spirit will teach, remind, guide into truth, testify about Jesus, and convict the world. John's understanding of the Spirit as the personal continuation of Jesus' presence gives the Christian community a basis for confident life after the departure of the historical Jesus."},
      {"title": "The Father-Son Relationship as the Model for Discipleship", "text": "John contains more teaching about the relationship between the Father and the Son than all the other gospels combined. The Son does nothing of himself but only what he sees the Father doing (5:19); he speaks not his own words but the Father's (14:24); he does the works the Father gives him (17:4). This total dependence and perfect obedience is not the Son's subordination but the pattern of all true human life before God — the image of God fully expressed in a human being. The disciples are invited into this same relationship: 'As the Father has sent me, even so I am sending you' (20:21)."}
    ]
  },

  "acts": {
    "key_people": [
      {"name": "Peter", "role": "The dominant figure of the first half (chs. 1-12) who preaches at Pentecost, heals the lame man, defends the gospel before the Sanhedrin, and opens the door to Gentiles at Cornelius's house"},
      {"name": "Paul", "role": "The dominant figure of the second half (chs. 13-28) whose three missionary journeys and journey to Rome trace the gospel's movement from Jerusalem to the centre of the world"},
      {"name": "Stephen", "role": "The first martyr whose speech (ch. 7) is the longest in Acts and a comprehensive reinterpretation of Israel's history culminating in the accusation that the religious leaders have killed the Righteous One"},
      {"name": "Barnabas", "role": "Paul's missionary partner whose role as bridge-builder (between Paul and the Jerusalem church; between the gospel and Gentile culture) is crucial for the mission's success"},
      {"name": "Lydia, Cornelius, the Philippian Jailer", "role": "Representative converts from different social locations whose stories illustrate the gospel's power across the boundaries of race, class, and religion"}
    ],
    "context": "Acts was written by Luke c. AD 80-90 as the second volume of his two-volume work. It traces the expansion of the gospel from Jerusalem (chs. 1-7), through Judaea and Samaria (chs. 8-12), to the ends of the earth as represented by Rome (chs. 13-28). The narrative is shaped by the promise of Acts 1:8 and driven by the Holy Spirit, who directs, empowers, and advances the mission at every decisive moment.",
    "christ_connection": "Acts is the story of the exalted and reigning Christ advancing his kingdom through the Spirit-empowered witness of his church. Every sermon in Acts centres on the resurrection of Jesus as the eschatological event that inaugurates the age of the Spirit (Joel 2:28-32 applied to Pentecost), establishes Jesus as Lord and Christ (2:36), and demands repentance and faith. The theological claim is that the Jesus of Nazareth who was crucified is the risen Lord who now sits at God's right hand (2:33-34) and from that position continues to act through his people in the world.",
    "key_verses": [
      {"ref": "Acts 1:8", "note": "'You will receive power when the Holy Spirit has come upon you, and you will be my witnesses in Jerusalem and in all Judea and Samaria, and to the end of the earth' — the book's structure in a sentence"},
      {"ref": "Acts 2:36", "note": "'Let all the house of Israel therefore know for certain that God has made him both Lord and Christ, this Jesus whom you crucified' — the kerygmatic core: the risen and exalted Jesus is Lord"},
      {"ref": "Acts 4:12", "note": "'And there is salvation in no one else, for there is no other name under heaven given among men by which we must be saved' — the book's exclusive claim in its most concentrated form"}
    ],
    "themes_detail": [
      {"title": "The Holy Spirit as the Book's Primary Agent", "text": "The Spirit is mentioned over 50 times in Acts and is the driving force behind every major development in the narrative: the Pentecost outpouring (2:1-4), the bold preaching of Peter (4:8), the direction of Philip (8:29, 39), the call of Paul and Barnabas (13:2), the Jerusalem Council's decision (15:28), and Paul's route changes (16:6-7). The Spirit is not a vague divine force but acts with specificity, speaks, forbids, and sends. Luke's narrative argues that what is happening in the church's expansion is not human religious achievement but God's own work through the Spirit who was poured out at Pentecost."},
      {"title": "The Gospel Crossing Boundaries", "text": "Acts is structured as a series of boundary-crossings that expand the definition of who belongs to God's people: from Jewish pilgrims (2:5-11) to Samaritans (ch. 8), to a God-fearing Ethiopian (8:26-40), to a Roman centurion (ch. 10-11), to Gentiles throughout the Mediterranean world (chs. 13-28). Each crossing is preceded by divine direction and confirmed by the Spirit's outpouring. The Jerusalem Council (ch. 15) makes the theological argument explicit: Gentiles receive the same Spirit as Jewish believers, demonstrating that God has accepted them. The gospel is, from the beginning, for all nations."},
      {"title": "The Continuity of the Mission with Israel's Story", "text": "Every major speech in Acts begins with Israel's history and argues that what is happening in Jesus and his community is the continuation and fulfilment of that story. Stephen's speech (ch. 7) retells the entire OT narrative to show that Israel had always resisted God's chosen deliverers; Paul's speech at Pisidian Antioch (13:16-41) moves from the Exodus to David to Jesus; and his speech at Athens (17:22-31) begins with creation. Acts presents Christianity not as a new religion but as the Jewish scriptures' own fulfilment — the covenant God at last fully enacting his saving purposes."},
      {"title": "Suffering and the Advance of the Gospel", "text": "Acts' structure suggests a counterintuitive pattern: persecution advances rather than hinders the gospel. The scattering after Stephen's martyrdom takes the gospel to Samaria and beyond (8:1-4); Paul's imprisonment leads to the Philippian jailer's conversion (16:25-34); his appeal to Caesar takes the gospel to Rome (27-28). The theology behind this pattern is explicit in Paul's speech to the Ephesian elders (20:24): the ministry must be completed regardless of what it costs, because it was received from the Lord Jesus. Suffering is not an obstacle to the mission but one of its primary vehicles."}
    ]
  },

  "romans": {
    "key_people": [
      {"name": "Paul", "role": "Author and apostle; writing to a church he did not found, Romans is his most systematic exposition of the gospel — intended both to introduce himself theologically and to address the Jewish-Gentile tensions in the Roman churches"},
      {"name": "Abraham", "role": "The central OT figure in Paul's argument (ch. 4); his faith-based justification before circumcision establishes that the principle of justification by faith is older than and independent of the Mosaic covenant"},
      {"name": "Adam", "role": "The figure whose one trespass brought condemnation to all (5:12-21); his role as representative head is the structural parallel to Christ as the second Adam whose obedience brings justification to many"}
    ],
    "context": "Romans was written c. AD 57 from Corinth, toward the end of Paul's third missionary journey, as he planned a trip to Rome and then Spain. The Roman church was a complex mixture of Jewish and Gentile Christians, and the tensions between these groups provide the pastoral context for the letter's theology. Romans is Paul's most sustained and systematic exposition of the gospel, written not to resolve a specific crisis but to lay a theological foundation for a church Paul hopes to partner with.",
    "christ_connection": "Romans presents the most comprehensive NT account of what Christ's death and resurrection accomplish. His death is a propitiation (3:25) that satisfies God's justice, a justification of the ungodly (4:5), a reconciliation of enemies (5:10), a condemnation of sin in the flesh (8:3), and a payment of the debt the law demanded (8:1-4). His resurrection is the guarantee of our own (6:5; 8:11) and the foundation of our hope (8:34). Romans 5's parallel between Adam and Christ argues that what Christ undoes is precisely what Adam did — so the scope of grace is at least as wide as the scope of sin.",
    "key_verses": [
      {"ref": "Romans 1:16-17", "note": "Paul's thesis: 'the gospel is the power of God for salvation to everyone who believes... For in it the righteousness of God is revealed from faith for faith' — justification by faith as the gospel's core"},
      {"ref": "Romans 3:23-24", "note": "'For all have sinned and fall short of the glory of God, and are justified by his grace as a gift, through the redemption that is in Christ Jesus' — the gospel in its most compressed form"},
      {"ref": "Romans 8:1", "note": "'There is therefore now no condemnation for those who are in Christ Jesus' — the conclusion of the argument of chs. 1-7 and the foundation of the assurance of chs. 8-11"},
      {"ref": "Romans 12:1-2", "note": "'Present your bodies as a living sacrifice... be transformed by the renewal of your mind' — the hinge between the gospel (1-11) and its ethical implications (12-16)"}
    ],
    "themes_detail": [
      {"title": "Justification by Faith Alone", "text": "Romans 1-5 is Paul's foundational argument for justification by faith: all humans (both Gentile and Jew) are under God's condemnation; God's righteousness is revealed in the gospel as a gift received through faith; Abraham is the paradigmatic example that this principle precedes and is independent of the Mosaic law. The term 'justified' (dikaioo) is forensic — a declaration of right standing before God — not a description of moral improvement. Its ground is Christ's obedience and atoning death; its instrument is faith alone; it is entirely by grace. This is Paul's answer to the fundamental question: how can sinful humans stand before a holy God?"},
      {"title": "The New Life in the Spirit", "text": "Romans 6-8 addresses the question that justification by grace alone inevitably raises: does this encourage sin? Paul's answer is a sustained argument about what union with Christ means: those united to Christ in his death are united to him in his resurrection, so that sin is no longer their master (6:1-14). The law, far from producing righteousness, actually stirs up sin (7:7-25) — a function the Spirit now fulfils positively (8:1-17). Chapter 8 is the book's experiential and pastoral climax: in the Spirit, Christians are sons, co-heirs with Christ, and recipients of a hope that encompasses the entire creation's renewal (8:18-25)."},
      {"title": "Israel, the Gentiles, and the Mystery of God's Plan", "text": "Romans 9-11, often neglected in systematic treatments of the book, addresses the most pressing theological question of Paul's day: if the gospel is for all nations, has God's word to Israel failed (9:6)? Paul's answer unfolds in three stages: God's election has always been selective within Israel (9:6-29); Israel's stumbling is partly responsible for the Gentile mission (10:19-11:12); and Israel's final restoration will accompany the fullness of the Gentile ingathering (11:25-32). The doxology closing chapter 11 (11:33-36) is Paul's acknowledgment that this mystery exceeds his comprehension — but not God's sovereignty."},
      {"title": "The Gospel's Ethical Implications", "text": "Romans 12-15 does not attach ethics to the gospel as an afterthought but as its direct consequence: 'I appeal to you therefore, brothers, by the mercies of God' (12:1). The mercy of the gospel is the motivation and foundation for the transformed life. The ethical section covers community relationships (12:3-16), response to enemies (12:17-21), submission to governing authorities (13:1-7), love as the law's fulfilment (13:8-10), and the strong-weak tensions in the Roman churches (14:1-15:13). The model throughout is Christ himself: 'Welcome one another as Christ has welcomed you' (15:7)."}
    ]
  },

  "1corinthians": {
    "key_people": [
      {"name": "Paul", "role": "Founder of the Corinthian church who writes to address divisions and disorders that have developed in his absence — the letter reveals more about life in an early church than any other NT document"},
      {"name": "Apollos", "role": "The eloquent Alexandrian teacher (Acts 18:24) whose ministry at Corinth has contributed to the party spirit; Paul carefully defuses the competition between himself and Apollos"},
      {"name": "Chloe's People", "role": "The unnamed messengers who bring Paul the news of the Corinthian divisions — 1:11 is the book's occasion statement, making the letter's context unusually transparent"}
    ],
    "context": "1 Corinthians was written c. AD 54-55 from Ephesus during Paul's third missionary journey. Corinth was Rome's wealthiest Greek city, a port renowned for commerce, sexual immorality, and social stratification. The church Paul founded there reflected the city's problems: faction, status competition, sexual license, and theological confusion. The letter addresses a long list of specific issues and reveals the complexity of applying the gospel to a highly stratified, cosmopolitan Roman city.",
    "christ_connection": "The cross is 1 Corinthians' recurring reference point for every pastoral problem: party spirit is overcome when the church is centred on the crucified Christ rather than on eloquent teachers (1:18-2:5); sexual immorality is addressed by the fact that our bodies are temples of the Spirit and members of Christ (6:15-20); the Lord's Supper is a proclamation of the Lord's death (11:26); resurrection hope is grounded entirely in Christ's resurrection as the firstfruits (15:20-23). Paul's pastoral method is consistently christocentric: the specific problems of the Corinthian church are addressed by returning to the implications of who Christ is and what he has done.",
    "key_verses": [
      {"ref": "1 Corinthians 1:18", "note": "'The word of the cross is folly to those who are perishing, but to us who are being saved it is the power of God' — the paradigm that overturns Corinthian status-wisdom"},
      {"ref": "1 Corinthians 13:4-7", "note": "The love chapter's description of agape: 'Love is patient and kind... bears all things, believes all things, hopes all things, endures all things' — the character of love that transcends every spiritual gift"},
      {"ref": "1 Corinthians 15:20", "note": "'But in fact Christ has been raised from the dead, the firstfruits of those who have fallen asleep' — the resurrection as the ground of all Christian hope, against those who denied it at Corinth"}
    ],
    "themes_detail": [
      {"title": "The Wisdom of the Cross versus the Wisdom of the World", "text": "The opening four chapters address the party spirit by exposing its theological root: Corinthian Christians are evaluating their teachers by the standards of Greco-Roman rhetoric and social status rather than by the gospel. Paul's response is radical: God's wisdom is the crucified Christ (1:24), which is folly by every human standard. This does not mean Christianity is anti-intellectual but that the cross reorders the hierarchy of values: the impressive, the powerful, the noble are not God's preferred instruments (1:26-29). Paul's own manner of speaking (2:1-5) is a deliberate embodiment of this principle."},
      {"title": "The Body of Christ and Spiritual Unity in Diversity", "text": "The image of the church as a body (ch. 12) is Paul's answer to Corinthian status-competition over spiritual gifts. The Spirit distributes gifts as he wills (12:11), and every member — including the ones who seem least honourable — is necessary and valuable (12:22-24). The church's diversity (many gifts, many members) is coordinated by the Spirit toward a unified end (one body, one Lord, one Spirit). Chapter 13 interrupts the gifts discussion to identify love as the way that gives every gift its value: without love, even the highest gifts are nothing."},
      {"title": "Resurrection as the Foundation of Christian Hope and Ethics", "text": "Chapter 15 is the longest treatment of the resurrection in the NT, addressing Corinthians who denied a future bodily resurrection. Paul's argument moves from historical evidence (Christ appeared to Peter, the Twelve, 500 brethren, James, Paul — 15:5-8) to theological logic (if there is no resurrection, Christ is not risen; if Christ is not risen, faith is vain; if faith is vain, you are still in your sins — 15:13-17) to eschatological vision (the resurrection body, the transformation of the dead, death's defeat at the last enemy — 15:35-57). The resurrection is not a detachable doctrinal bonus but the load-bearing wall of the entire structure."},
      {"title": "Christian Freedom and Its Limits", "text": "Several sections of the letter deal with the principle 'all things are lawful but not all things are beneficial' (6:12; 10:23). The issue is how Christian freedom should be governed in the context of the community: freedom to eat food sacrificed to idols must be limited by concern for the weaker brother's conscience (chs. 8-10); freedom regarding sexual relations is limited by the body's status as a temple of the Spirit (6:12-20) and by the call to holiness (7:1-40). Paul's consistent principle is that Christian freedom is exercised in the service of love — the freedom to give up one's rights for the sake of another, as Christ gave up his glory for us."}
    ]
  },

  "2corinthians": {
    "key_people": [
      {"name": "Paul", "role": "Writing the most personally revealing of his letters, Paul defends his apostolic ministry against 'super-apostles' who have challenged his authority, and pours out his own suffering and weakness as evidence of genuine apostleship"},
      {"name": "Titus", "role": "Paul's co-worker and emissary who brought good news of the Corinthians' repentance (7:6-7) and is being sent again with this letter to complete the collection for Jerusalem"}
    ],
    "context": "2 Corinthians was written c. AD 55-57 from Macedonia, after a painful visit to Corinth and a severe letter that preceded this one. The church's response to the severe letter was largely positive, but a group of opponents ('super-apostles', 11:5) were still undermining Paul's authority by contrasting his weak physical presence and refusal of payment with what they claimed was genuine apostolic power and status. The letter is Paul's most personal and his most sustained reflection on the nature of apostolic ministry.",
    "christ_connection": "The paradox of Paul's ministry — power through weakness, life through death — mirrors and participates in the pattern of Christ's own ministry. The 'treasure in jars of clay' passage (4:7-12) makes this explicit: the extraordinary power of the gospel is revealed precisely through the apostle's weakness, so that it is clearly God's power and not human achievement. The theology of the cross is not just Paul's message but the form of his ministry: 'always carrying in the body the death of Jesus, so that the life of Jesus may also be manifested in our bodies' (4:10). The new covenant ministry Paul describes in ch. 3 is the ministry of the Spirit who transforms believers into the image of Christ.",
    "key_verses": [
      {"ref": "2 Corinthians 4:7", "note": "'We have this treasure in jars of clay, to show that the surpassing power belongs to God and not to us' — the theology of weakness and power that governs Paul's entire apostolic self-understanding"},
      {"ref": "2 Corinthians 5:21", "note": "'For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God' — the most concentrated NT statement of imputation and substitutionary exchange"},
      {"ref": "2 Corinthians 12:9", "note": "'My grace is sufficient for you, for my power is made perfect in weakness' — the Lord's direct answer to Paul's thorn in the flesh, paradigmatic for all Christian suffering"}
    ],
    "themes_detail": [
      {"title": "The Theology of Weakness and Power", "text": "2 Corinthians is Paul's sustained argument that the pattern of Christ's death and resurrection — weakness that becomes the vehicle of divine power — defines authentic apostolic ministry. His catalogue of sufferings (4:8-9; 6:4-10; 11:23-29) is not self-pity but theological demonstration: these sufferings are evidence of genuine apostleship, not its refutation. The super-apostles who impress Corinth with their eloquence and social status are measuring ministry by the wrong standard. The 'thorn in the flesh' episode (12:7-10) is the most personal expression of this theology: God's deliberate refusal to remove weakness so that his power might be displayed through it."},
      {"title": "The Ministry of the New Covenant", "text": "Chapters 3-4 contain Paul's most developed comparison of old and new covenants. The Mosaic ministry, though glorious, was a ministry of condemnation and death — the law exposed sin but could not remove it. The new covenant ministry is a ministry of the Spirit that gives life, of righteousness, and whose glory is surpassing and permanent. The veil over Moses' face (Exod 34:33-35) was to hide the fading glory; the veil over Israel's heart (3:14-15) prevents them from seeing Christ in their own scriptures. The Spirit lifts this veil, and beholding Christ's glory transforms believers progressively into his image (3:18)."},
      {"title": "Reconciliation as the Gospel's Content and Paul's Ministry", "text": "2 Corinthians 5:14-21 contains one of the NT's most compressed accounts of the atonement: Christ died for all so that those who live might live for him; God was in Christ reconciling the world to himself; he made Christ to be sin so that we might become God's righteousness. The theological content (reconciliation) and its ministerial application (Paul's own ministry of reconciliation) are inseparable — Paul does not just preach about reconciliation but enacts it as an ambassador, making an appeal on Christ's behalf: 'be reconciled to God.' The gospel is both an announcement and an invitation that requires a personal response."},
      {"title": "Generosity as Participation in the Grace of Christ", "text": "Chapters 8-9 address the collection for the Jerusalem poor with a sustained theology of generous giving. The foundation is christological: 'you know the grace of our Lord Jesus Christ, that though he was rich, yet for your sake he became poor, so that you by his poverty might become rich' (8:9). Generosity is not fundraising strategy but participation in the self-giving pattern of Christ's incarnation. The principle of equality (8:13-14) envisions the church as a community of mutual provision; the promise of blessing for the generous giver (9:6-15) is grounded in God's own inexhaustible generosity — 'Thanks be to God for his inexpressible gift' (9:15)."}
    ]
  },

  "galatians": {
    "key_people": [
      {"name": "Paul", "role": "Author and founder of the Galatian churches who writes with unusual emotional intensity ('I am astonished', 1:6; 'O foolish Galatians!', 3:1) because the gospel itself is at stake"},
      {"name": "The Agitators", "role": "Unnamed Jewish-Christian teachers who have persuaded the Galatians to adopt circumcision and Torah observance as necessary for full membership in God's people — Paul's theological opponents throughout"},
      {"name": "Peter (Cephas)", "role": "Rebuked publicly by Paul at Antioch (2:11-14) for withdrawing from table fellowship with Gentile Christians under pressure from James's people — the incident that precipitates the letter's theological argument"}
    ],
    "context": "Galatians was written c. AD 48-49 (South Galatian theory) or AD 53-55 (North Galatian theory) in response to a crisis: Jewish-Christian teachers had persuaded the Galatian churches that circumcision and Torah observance were necessary for full covenant membership. Paul regards this as a different gospel that perverts the gospel of Christ (1:7). The letter is his most urgent and combative, beginning without a thanksgiving and calling down a curse on those who preach a different gospel.",
    "christ_connection": "Galatians argues that the cross accomplishes what the Torah could not: it redeems from the law's curse (3:13), brings the Spirit through faith (3:14), makes all who believe Abraham's descendants and heirs of the promise (3:29), and establishes the new humanity in which ethnic, social, and gender distinctions do not determine covenant standing (3:28). Christ crucified (3:1) is Paul's summary of the entire gospel against every form of works-righteousness. The 'no longer I who live, but Christ who lives in me' (2:20) is the personal form of this reality: the Christian life is the life of the risen Christ lived through the believer by faith.",
    "key_verses": [
      {"ref": "Galatians 2:20", "note": "'I have been crucified with Christ. It is no longer I who live, but Christ who lives in me' — the most personal expression of union with Christ in Paul's letters"},
      {"ref": "Galatians 3:13", "note": "'Christ redeemed us from the curse of the law by becoming a curse for us' — substitutionary atonement in its starkest Pauline form, grounded in Deut 21:23"},
      {"ref": "Galatians 3:28", "note": "'There is neither Jew nor Greek, there is neither slave nor free, there is no male and female, for you are all one in Christ Jesus' — the gospel's social implications: covenant standing is equal regardless of ethnicity, status, or gender"},
      {"ref": "Galatians 5:1", "note": "'For freedom Christ has set us free; stand firm therefore, and do not submit again to a yoke of slavery' — the practical summary of the entire letter's argument"}
    ],
    "themes_detail": [
      {"title": "Justification by Faith Against Works of the Law", "text": "Galatians 2-3 is Paul's most polemical argument for justification by faith: no one is justified by works of the law (2:16); the law cannot give life (3:21); it served as a guardian until Christ came (3:24). The Antioch incident (2:11-14) shows that this is not an abstract doctrine but a practical gospel issue — Peter's behaviour was 'not in step with the truth of the gospel' because it implied that Gentile Christians needed to Judaize to be fully accepted. The theological argument and the social reality are inseparable: a gospel that requires Torah observance for full membership is not a gospel at all."},
      {"title": "The Promise to Abraham as the Prior and Normative Covenant", "text": "Galatians 3-4 uses a striking legal argument: a ratified covenant cannot be annulled or modified by a later agreement (3:15). God's covenant with Abraham was a promise received through faith; the Mosaic law, which came 430 years later, cannot retroactively change the terms. The law's function was not to replace the promise but to serve as a guardian until the promised seed (Christ) arrived. Now that Christ has come, the guardian's role is completed: all who are 'in Christ' — regardless of ethnic origin — are Abraham's offspring and heirs of the promise."},
      {"title": "The Spirit and the Flesh", "text": "Chapters 5-6 address the ethical corollary of justification by faith: does freedom from the law produce moral license? Paul's answer is the life of the Spirit. The Spirit produces fruit — love, joy, peace, patience, kindness, goodness, faithfulness, gentleness, self-control (5:22-23) — that no list of Torah regulations can produce. The freedom of the gospel is not freedom to indulge the flesh but freedom to serve one another in love (5:13-14). Walking by the Spirit and crucifying the flesh are not human achievement but the life of those who have been united to Christ's death and resurrection."},
      {"title": "The New Creation and the Unity of the Gospel Community", "text": "Galatians 6:15 provides the book's ultimate perspective: 'Neither circumcision nor uncircumcision counts for anything, but a new creation.' The gospel does not simply modify the existing order (adding Gentiles to an Israel-shaped community) but inaugurates a new creation in which the old ethnic, social, and gender categories no longer determine covenant standing. The community that lives out Galatians 3:28 — genuinely inclusive across every human boundary — is a sign of the new creation's arrival. Paul's table fellowship with Gentiles that Peter withdrew from was not just a social preference but a sign of the new age."}
    ]
  },

  "ephesians": {
    "key_people": [
      {"name": "Paul", "role": "Author (the letter claims Pauline authorship; if pseudonymous, it represents a Pauline school's mature reflection on his theology) writing from prison with the broadest possible horizon for the church's identity"},
      {"name": "Tychicus", "role": "The letter's carrier (6:21-22) who will supplement its contents in person — a reminder that Pauline letters were oral events, read aloud and explained by trusted emissaries"}
    ],
    "context": "Ephesians was written c. AD 60-62 from Rome (if authentic Pauline), possibly as a circular letter to several Asian churches rather than specifically to Ephesus (the earliest manuscripts omit 'in Ephesus' in 1:1). The letter lacks the personal greetings and specific controversy that characterise most Pauline letters, suggesting a more general audience. It represents Paul's most cosmic and ecclesiological vision, addressed to churches that need to understand their place in God's eternal purposes.",
    "christ_connection": "Ephesians presents the most comprehensive NT picture of the cosmic scope of Christ's work. He has been raised above every ruler, authority, power, and dominion (1:21) and given as head over all things to the church (1:22); he has broken down the wall between Jew and Gentile, creating one new humanity in himself (2:14-15); he fills everything in every way (1:23; 4:10). The church, as his body and fullness, is the visible expression of his cosmic rule — the place where the multiform wisdom of God is made known to the powers and authorities (3:10). Marriage is a mystery that images Christ and the church (5:32).",
    "key_verses": [
      {"ref": "Ephesians 1:4", "note": "'He chose us in him before the foundation of the world, that we should be holy and blameless before him' — election in Christ as the foundation of the entire letter's theology of grace"},
      {"ref": "Ephesians 2:8-9", "note": "'For by grace you have been saved through faith. And this is not your own doing; it is the gift of God, not a result of works, so that no one may boast' — the most concise statement of salvation by grace through faith in the NT"},
      {"ref": "Ephesians 3:10", "note": "'Through the church the manifold wisdom of God might now be made known to the rulers and authorities in the heavenly places' — the church's cosmic purpose: to display God's wisdom to spiritual powers"},
      {"ref": "Ephesians 4:4-6", "note": "The sevenfold unity: one body, one Spirit, one hope, one Lord, one faith, one baptism, one God and Father — the ontological basis for the practical unity the letter calls for"}
    ],
    "themes_detail": [
      {"title": "Election, Adoption, and the Eternal Purpose of God", "text": "Ephesians 1:3-14 is one long, breathless sentence in Greek (a single period in the Greek text) cataloguing the spiritual blessings that belong to those who are in Christ. Election before the foundation of the world (1:4), predestination to adoption (1:5), redemption through his blood (1:7), and the sealing of the Spirit (1:13-14) are all anchored in God's sovereign, prior choice. Paul's purpose in this opening is doxological: the goal of these purposes is 'the praise of his glorious grace' (1:6, 12, 14). The entire letter stands under the sign of grace — undeserved, unconditional, sovereign."},
      {"title": "The Church as the New Humanity", "text": "Ephesians 2:11-22 presents the church as the most radical social reality in the world: Jew and Gentile, formerly separated by the law's 'dividing wall of hostility' (2:14), have been made one new humanity in Christ's body through the cross. This is not merely ethnic reconciliation but a new creation — a community that transcends the deepest division in the ancient world. The church's unity across ethnic, social, and cultural lines is therefore not a secondary sociological concern but the very body of Christ, the visible expression of his cosmic reconciling work. Failure to maintain this unity contradicts the gospel."},
      {"title": "The Cosmic Lordship of Christ and the Powers", "text": "Ephesians develops a distinctive theology of 'principalities and powers' — spiritual beings that govern various domains of the created order and have been subjected to Christ through his resurrection and exaltation (1:21; 3:10; 6:12). The church's existence as the multiethnic body of Christ is a public demonstration to these powers that Christ's victory has been accomplished (3:10). The spiritual warfare of 6:10-20 is not about individual moral struggle but about maintaining the church's identity as the community of the new creation against the constant pressure of the powers that resist God's purposes."},
      {"title": "The Household Codes and the Gospel's Social Vision", "text": "Ephesians 5:22-6:9 (wives/husbands, children/parents, slaves/masters) has been the subject of intense controversy, but its theological structure is clear: every relationship is governed by 'in the Lord' and by the pattern of Christ's self-giving love. The husband's headship is modelled on Christ's self-emptying sacrifice (5:25-27), not on Roman paterfamilias authority. The code both accepts the basic structure of the Greco-Roman household (it does not call for immediate revolution) and profoundly subverts it: every superior is called to serve rather than dominate, every relationship is transformed by the gospel's pattern of mutual submission (5:21)."}
    ]
  }
}


def enrich(book_id, extras):
    path = os.path.join(OUT, book_id + '.json')
    if not os.path.exists(path):
        print(f'  SKIP  {book_id} (file not found)')
        return
    with open(path, encoding='utf-8') as f:
        data = json.load(f)
    if 'key_people' in data:
        print(f'  skip  {book_id} (already enriched)')
        return
    for key in ('key_people', 'context', 'christ_connection', 'key_verses', 'themes_detail'):
        if key in extras:
            data[key] = extras[key]
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f'  enriched: {book_id}')


for book_id, extras in ENRICHMENTS.items():
    enrich(book_id, extras)

print(f'\nDone — {len(ENRICHMENTS)} books processed: {", ".join(ENRICHMENTS.keys())}')
